#include <bits/stdc++.h>
using namespace std;
int n,m,a[5000005],d[5000005],minn=100;
int main() {
	cin>>n>>m;
	for(int i=1; i<=n; i++) {
		cin>>a[i];
		d[i]=a[i]-a[i-1];
	}
	while(m--) {
		int x,y,z;
		cin>>x>>y>>z;
		d[x]+=z;
		d[y+1]-=z;
	}

	for(int i=1; i<=n; i++) {
		a[i]=a[i-1]+d[i];
		if(a[i]<minn) {
			minn=a[i];
		}
	}
	cout<<minn;
	return 0;
}
